queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?sectionname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSections ?child ; p:hasFinancial_Statements ?parent . } GROUP BY ?child }
  ?child p:SectionName ?sectionname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Financial_Statements } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?sectionname WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSections ?child ; p:hasFinancial_Statements ?parent . } GROUP BY ?child }
  ?child p:SectionName ?sectionname .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Financial_Statements } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?sectionname WHERE {
  ?financial_statements_sections a :Financial_Statements_Sections .
  ?sections a :Sections .
  ?financial_statements_sections p:hasSections ?sections .
  ?financial_statements a :Financial_Statements .
  ?financial_statements_sections p:hasFinancial_Statements ?financial_statements .
  ?financial_statements p:name ?name .
  ?sections p:SectionName ?sectionname .
} }
}
